return ['domain'=>'brikpanel','plural-forms'=>'nplurals=3; plural=(n==1 ? 0 : n%10>=2 && n%10<=4 && (n%100<10 || n%100>=20) ? 1 : 2);','language'=>'pl_PL','project-id-version'=>'BrikPanel','pot-creation-date'=>'2026-05-24T17:14:30+00:00','po-revision-date'=>'2026-05-23','x-generator'=>'Claude (BrikPanel auto-translation)','messages'=>['BrikPanel: WooCommerce Admin Dashboard Theme'=>'BrikPanel: motyw panelu administracyjnego WooCommerce','Beautiful and modern Shopify-style WooCommerce admin panel & dashboard, fully free, forever.'=>'Piękny i nowoczesny panel administracyjny oraz pulpit WooCommerce w stylu Shopify, w pełni darmowy na zawsze.','Brksoft'=>'Brksoft','https://brksoft.com/'=>'https://brksoft.com/','WooCommerce is not active on this site, so BrikPanel features are disabled here. Activate WooCommerce to enable BrikPanel.'=>'WooCommerce nie jest aktywne na tej witrynie, więc funkcje BrikPanel są tutaj wyłączone. Aktywuj WooCommerce, aby włączyć BrikPanel.','Order statusReturn Draft'=>'Szkic zwrotu','Return Draft <span class="count">(%s)</span>'=>'Szkic zwrotu <span class="count">(%s)</span>' . "\0" . 'Szkice zwrotów <span class="count">(%s)</span>' . "\0" . 'Szkiców zwrotów <span class="count">(%s)</span>','Order statusChange'=>'Wymiana','Change <span class="count">(%s)</span>'=>'Wymiana <span class="count">(%s)</span>' . "\0" . 'Wymiany <span class="count">(%s)</span>' . "\0" . 'Wymian <span class="count">(%s)</span>','Settings'=>'Ustawienia','Ad Platforms integration'=>'Integracja Ad Platforms','Pull daily ad spend from Google Ads and Meta Ads to calculate true ROAS and Net Profit on the dashboard. Currently in beta — turn it off below to hide the admin page and stop all background sync jobs. Your connections stay saved.'=>'Pobieraj dzienne wydatki reklamowe z Google Ads i Meta Ads, aby obliczać rzeczywiste ROAS i zysk netto na pulpicie. Obecnie w wersji beta — wyłącz poniżej, aby ukryć stronę administracyjną i zatrzymać wszystkie zadania synchronizacji w tle. Twoje połączenia pozostaną zapisane.','Enable Ad Platforms integration'=>'Włącz integrację Ad Platforms','When on, the Ad Platforms admin menu, daily sync, and dashboard ROAS / Net Profit cards are active. When off, the module is dormant: no menu item, no scheduled sync, no dashboard cards.'=>'Po włączeniu aktywne są menu administracyjne Ad Platforms, codzienna synchronizacja oraz karty ROAS i zysku netto na pulpicie. Po wyłączeniu moduł jest uśpiony: brak pozycji w menu, brak zaplanowanej synchronizacji, brak kart na pulpicie.','Beta'=>'Beta','ROAS'=>'ROAS','Google Ads connection was revoked for security. Please reconnect.'=>'Połączenie z Google Ads zostało unieważnione ze względów bezpieczeństwa. Połącz ponownie.','Not connected to Google Ads.'=>'Brak połączenia z Google Ads.','The BrikPanel proxy returned an unverifiable response and was rejected.'=>'Serwer proxy BrikPanel zwrócił odpowiedź, której nie można zweryfikować, i została ona odrzucona.','Request to Google Ads failed after retries.'=>'Żądanie do Google Ads nie powiodło się po próbach ponowienia.','Meta Ads connection was revoked for security. Please reconnect.'=>'Połączenie z Meta Ads zostało unieważnione ze względów bezpieczeństwa. Połącz ponownie.','Not connected to Meta Ads.'=>'Brak połączenia z Meta Ads.','Request to Meta Ads failed after retries.'=>'Żądanie do Meta Ads nie powiodło się po próbach ponowienia.','Permission denied.'=>'Brak uprawnień.','Unknown platform.'=>'Nieznana platforma.','This connection is not available yet — it is pending platform approval.'=>'To połączenie nie jest jeszcze dostępne — oczekuje na zatwierdzenie przez platformę.','Could not reach the BrikPanel proxy. Please try again in a moment.'=>'Nie udało się połączyć z serwerem proxy BrikPanel. Spróbuj ponownie za chwilę.','Could not start OAuth: proxy returned an error.'=>'Nie udało się rozpocząć OAuth: serwer proxy zwrócił błąd.','Disconnected.'=>'Rozłączono.','OAuth session expired. Please try connecting again.'=>'Sesja OAuth wygasła. Spróbuj połączyć się ponownie.','Unknown platform in OAuth state.'=>'Nieznana platforma w stanie OAuth.','OAuth callback was for a different user. Aborted.'=>'Wywołanie zwrotne OAuth dotyczyło innego użytkownika. Anulowano.','Could not reach the BrikPanel proxy.'=>'Nie udało się połączyć z serwerem proxy BrikPanel.','OAuth redemption failed. Please try connecting again.'=>'Wymiana OAuth nie powiodła się. Spróbuj połączyć się ponownie.','Could not save tokens. Please try again.'=>'Nie udało się zapisać tokenów. Spróbuj ponownie.','Google Ads connected.'=>'Połączono Google Ads.','Meta Ads connected.'=>'Połączono Meta Ads.','Ad Platforms'=>'Ad Platforms','Beta feature'=>'Funkcja beta','Connecting…'=>'Łączenie…','Disconnect this platform? Your synced spend data will be deleted.'=>'Rozłączyć tę platformę? Zsynchronizowane dane o wydatkach zostaną usunięte.','Syncing…'=>'Synchronizowanie…','Sync queued. Refresh the page in a moment.'=>'Synchronizacja w kolejce. Odśwież stronę za chwilę.','Saved.'=>'Zapisano.','Loading accounts…'=>'Ładowanie kont…','No ad accounts found for this connection.'=>'Nie znaleziono kont reklamowych dla tego połączenia.','Something went wrong. Please try again.'=>'Coś poszło nie tak. Spróbuj ponownie.','No errors logged.'=>'Brak zarejestrowanych błędów.','Connected'=>'Połączono','Not connected'=>'Nie połączono','Pick a primary account first.'=>'Najpierw wybierz główne konto.','Manager'=>'Menedżer','Loading history… %1$d of %2$d 90-day chunks done'=>'Ładowanie historii… %1$d z %2$d 90-dniowych fragmentów ukończono','Connect this platform first.'=>'Najpierw połącz tę platformę.','Pick an account before saving.'=>'Wybierz konto przed zapisaniem.','Account saved. Loading 3 years of history in the background — refresh the page in a few minutes to see it.'=>'Konto zapisane. Ładowanie 3 lat historii w tle — odśwież stronę za kilka minut, aby zobaczyć wyniki.','Account saved.'=>'Konto zapisane.','Synced %1$d row(s) across %2$d day(s).'=>'Zsynchronizowano %1$d wierszy z %2$d dni.','Ad spend daily sync'=>'Codzienna synchronizacja wydatków reklamowych','Pulls yesterday plus the last 7 days of spend from each connected ad platform.'=>'Pobiera wczorajsze dane oraz ostatnie 7 dni wydatków z każdej połączonej platformy reklamowej.','Ad spend backfill chunk'=>'Fragment uzupełniania wydatków reklamowych','One 90-day slice of the initial historical pull when an ad platform is first connected.'=>'Jeden 90-dniowy fragment początkowego pobierania historii po pierwszym połączeniu platformy reklamowej.','Not connected.'=>'Nie połączono.','Pending Google approval'=>'Oczekuje na zatwierdzenie przez Google','Google Ads needs to approve our API access before this connection can go live. It will be enabled automatically once approved — no action is needed from you.'=>'Google Ads musi zatwierdzić nasz dostęp API, zanim to połączenie zostanie uruchomione. Zostanie ono włączone automatycznie po zatwierdzeniu — z Twojej strony nie jest wymagane żadne działanie.','Connect Google Ads'=>'Połącz Google Ads','Pending Meta approval'=>'Oczekuje na zatwierdzenie przez Meta','Meta needs to review our app before this connection can go live. It will be enabled automatically once approved — no action is needed from you.'=>'Meta musi zweryfikować naszą aplikację, zanim to połączenie zostanie uruchomione. Zostanie ono włączone automatycznie po zatwierdzeniu — z Twojej strony nie jest wymagane żadne działanie.','Connect Meta Ads'=>'Połącz Meta Ads','Coming soon'=>'Wkrótce','BrikPanel will request read-only access to your Google Ads accounts. We only pull total daily spend, impressions and clicks — no campaign management.'=>'BrikPanel poprosi o dostęp tylko do odczytu do Twoich kont Google Ads. Pobieramy wyłącznie łączne dzienne wydatki, wyświetlenia i kliknięcia — bez zarządzania kampaniami.','BrikPanel will request read-only access (ads_read) to your Meta ad accounts. We only pull total daily spend, impressions and clicks.'=>'BrikPanel poprosi o dostęp tylko do odczytu (ads_read) do Twoich kont reklamowych Meta. Pobieramy wyłącznie łączne dzienne wydatki, wyświetlenia i kliknięcia.','Connected as'=>'Połączono jako','(email not shared)'=>'(adres e-mail nie został udostępniony)','Primary ad account'=>'Główne konto reklamowe','BrikPanel pulls spend from this one account. To switch later, choose another from the list and click Save.'=>'BrikPanel pobiera wydatki z tego jednego konta. Aby później zmienić, wybierz inne z listy i kliknij Zapisz.','Click "Load accounts" to choose…'=>'Kliknij „Załaduj konta”, aby wybrać…','Load accounts'=>'Załaduj konta','Save'=>'Zapisz','Manager (MCC) account ID — optional'=>'ID konta menedżera (MCC) — opcjonalne','Only fill in if you access the chosen account through a Google Ads manager. Digits only, no dashes.'=>'Wypełnij tylko, jeśli uzyskujesz dostęp do wybranego konta przez menedżera Google Ads. Tylko cyfry, bez myślników.','Last successful sync'=>'Ostatnia udana synchronizacja','ago'=>'temu','(last attempt failed — check the error log)'=>'(ostatnia próba nie powiodła się — sprawdź dziennik błędów)','Sync now'=>'Synchronizuj teraz','Re-authorize'=>'Autoryzuj ponownie','Disconnect'=>'Rozłącz','Connect Google Ads and Meta Ads so BrikPanel can show real ROAS and Net Profit on the dashboard.'=>'Połącz Google Ads i Meta Ads, aby BrikPanel mógł pokazywać rzeczywiste ROAS i zysk netto na pulpicie.','Google Ads'=>'Google Ads','Pulls daily total spend, impressions and clicks from one Google Ads account.'=>'Pobiera dzienne łączne wydatki, wyświetlenia i kliknięcia z jednego konta Google Ads.','Meta Ads'=>'Meta Ads','Pulls daily total spend, impressions and clicks from one Meta ad account (Facebook + Instagram).'=>'Pobiera dzienne łączne wydatki, wyświetlenia i kliknięcia z jednego konta reklamowego Meta (Facebook + Instagram).','How it works'=>'Jak to działa','Connect each platform once. Tokens are encrypted on this server and never leave it.'=>'Połącz każdą platformę jeden raz. Tokeny są szyfrowane na tym serwerze i nigdy go nie opuszczają.','On first connect, the last 3 years of daily spend are loaded in the background (90-day chunks every 30 seconds).'=>'Przy pierwszym połączeniu ostatnie 3 lata dziennych wydatków są ładowane w tle (90-dniowe fragmenty co 30 sekund).','After that, the last 7 days are refreshed once per day to capture late corrections.'=>'Następnie ostatnie 7 dni jest odświeżane raz dziennie, aby uchwycić późniejsze korekty.','Spend is stored in the ad account currency — the dashboard shows ad-currency totals next to your store revenue so you can compare them directly.'=>'Wydatki są przechowywane w walucie konta reklamowego — pulpit pokazuje sumy w walucie reklam obok przychodów sklepu, aby można je było bezpośrednio porównać.','Recent errors'=>'Ostatnie błędy','Last 50 entries from the sync log. Token values are redacted before storage.'=>'Ostatnie 50 wpisów z dziennika synchronizacji. Wartości tokenów są usuwane przed zapisem.','View log'=>'Zobacz dziennik','Clear log'=>'Wyczyść dziennik','System default'=>'Domyślna systemowa','Appearance'=>'Wygląd','Customize how the BrikPanel admin interface looks. Changes apply to dashboard, products, orders, coupons, segments, the top bar, sidebar, and the modern login page. The rest of WordPress admin is untouched.'=>'Dostosuj wygląd interfejsu administracyjnego BrikPanel. Zmiany dotyczą pulpitu, produktów, zamówień, kuponów, segmentów, górnego paska, paska bocznego oraz nowoczesnej strony logowania. Reszta panelu WordPress pozostaje nienaruszona.','Interface font'=>'Czcionka interfejsu','Pick the typeface used across BrikPanel. "System default" stays on your operating system\'s native font (no external request). Other choices load a single Google Fonts stylesheet with display: swap.'=>'Wybierz krój pisma używany w całym BrikPanel. „Domyślna systemowa” pozostaje przy natywnej czcionce systemu operacyjnego (bez zewnętrznych żądań). Inne opcje ładują pojedynczy arkusz stylów Google Fonts z display: swap.','Accent color'=>'Kolor akcentu','Primary color used for buttons, focus rings, toggles, and active highlights. The BrikPanel default is a near-black gray (#303030); pick anything you like.'=>'Główny kolor używany dla przycisków, obwódek fokusa, przełączników i aktywnych wyróżnień. Domyślny BrikPanel to niemal czarna szarość (#303030); wybierz, co lubisz.','Custom brand logo'=>'Niestandardowe logo marki','Replace the BrikPanel mark in the admin top bar and on the modern login page with your own brand logo. When off, the default BrikPanel icon and your site name are shown.'=>'Zastąp znak BrikPanel w górnym pasku administratora i na nowoczesnej stronie logowania własnym logo marki. Po wyłączeniu wyświetlana jest domyślna ikona BrikPanel i nazwa witryny.','Brand logo image'=>'Obraz logo marki','Pick or upload an image from your media library. The same logo is used in the admin top bar and on the modern login page. PNG or SVG with transparent background gives the cleanest result. Recommended size: 256×256 px or wider.'=>'Wybierz lub prześlij obraz z biblioteki mediów. To samo logo jest używane w górnym pasku administratora i na nowoczesnej stronie logowania. PNG lub SVG z przezroczystym tłem daje najczystszy efekt. Zalecany rozmiar: 256×256 pikseli lub większy.','No logo selected'=>'Nie wybrano logo','Replace logo'=>'Zastąp logo','Select logo'=>'Wybierz logo','Remove'=>'Usuń','Select brand logo'=>'Wybierz logo marki','Use this image'=>'Użyj tego obrazu','Product Image Health'=>'Stan obrazów produktów','Scanning… %1$s / %2$s products'=>'Skanowanie… %1$s / %2$s produktów','No product images found yet.'=>'Nie znaleziono jeszcze obrazów produktów.','%1$s%% oversized (%2$s of %3$s) · %4$s%% modern format'=>'%1$s%% za dużych (%2$s z %3$s) · %4$s%% w nowoczesnym formacie','Add product images to start the health check.'=>'Dodaj obrazy produktów, aby rozpocząć kontrolę stanu.','%1$s product images are larger than 1 MB. Modern formats (WebP / AVIF) cover %2$s%% of your library. Missing files: %3$s.'=>'%1$s obrazów produktów ma rozmiar większy niż 1 MB. Nowoczesne formaty (WebP / AVIF) obejmują %2$s%% Twojej biblioteki. Brakujące pliki: %3$s.','No products yet — nothing to check.'=>'Brak produktów — nie ma czego sprawdzać.','Add at least one published product to enable image health checks.'=>'Dodaj co najmniej jeden opublikowany produkt, aby włączyć kontrole stanu obrazów.','Install %s to compress images and convert to WebP/AVIF automatically.'=>'Zainstaluj %s, aby automatycznie kompresować obrazy i konwertować je do WebP/AVIF.','Install plugin'=>'Zainstaluj wtyczkę','%1$s product images (%2$s%%) are larger than 1 MB. These slow down your product pages and hurt SEO. Compress them to under 200 KB where possible.'=>'%1$s obrazów produktów (%2$s%%) ma rozmiar większy niż 1 MB. Spowalniają one strony produktów i szkodzą SEO. Skompresuj je do mniej niż 200 KB tam, gdzie to możliwe.','Only %s%% of your product images use WebP / AVIF. Modern formats are 30–50%% smaller than JPEG/PNG with no visible quality loss.'=>'Tylko %s%% obrazów produktów używa WebP / AVIF. Nowoczesne formaty są o 30–50%% mniejsze niż JPEG/PNG bez widocznej utraty jakości.','%s product images point to files that no longer exist on disk. Re-upload them or detach the missing media references.'=>'%s obrazów produktów wskazuje na pliki, które już nie istnieją na dysku. Prześlij je ponownie lub odłącz brakujące odwołania do mediów.','Your product images are well-optimised. Keep an eye on this metric as you upload new products.'=>'Twoje obrazy produktów są dobrze zoptymalizowane. Obserwuj ten wskaźnik podczas dodawania nowych produktów.','BrikControl: Full Health Scan'=>'BrikControl: pełne skanowanie stanu','Runs every BrikControl check and writes results to the dashboard.'=>'Uruchamia każdą kontrolę BrikControl i zapisuje wyniki na pulpicie.','BrikControl: Scan Batch'=>'BrikControl: partia skanowania','Processes a single batch of a long-running BrikControl check.'=>'Przetwarza pojedynczą partię długo trwającej kontroli BrikControl.','Store Health'=>'Stan sklepu','Rescan now'=>'Skanuj ponownie teraz','Scan queued — refreshing…'=>'Skanowanie w kolejce — odświeżanie…','Could not start scan.'=>'Nie udało się rozpocząć skanowania.','Not scanned yet'=>'Jeszcze nie zeskanowano','Scanning in background…'=>'Skanowanie w tle…','just now'=>'przed chwilą','Scanning {cursor} / {total} products…'=>'Skanowanie {cursor} / {total} produktów…','All checks passing'=>'Wszystkie kontrole zaliczone','Open Store Health'=>'Otwórz Stan sklepu','Last scan'=>'Ostatnie skanowanie','Scanning…'=>'Skanowanie…','%s min ago'=>'%s minutę temu' . "\0" . '%s minuty temu' . "\0" . '%s minut temu','%s h ago'=>'%s godzinę temu' . "\0" . '%s godziny temu' . "\0" . '%s godzin temu','%s d ago'=>'%s dzień temu' . "\0" . '%s dni temu' . "\0" . '%s dni temu','You do not have permission to access this page.'=>'Nie masz uprawnień do dostępu do tej strony.','Not scanned yet — run a scan to see results.'=>'Jeszcze nie zeskanowano — uruchom skanowanie, aby zobaczyć wyniki.','%s critical store health issue'=>'%s krytyczny problem ze stanem sklepu' . "\0" . '%s krytyczne problemy ze stanem sklepu' . "\0" . '%s krytycznych problemów ze stanem sklepu','%s store health warning'=>'%s ostrzeżenie dotyczące stanu sklepu' . "\0" . '%s ostrzeżenia dotyczące stanu sklepu' . "\0" . '%s ostrzeżeń dotyczących stanu sklepu','Store health: all checks passing'=>'Stan sklepu: wszystkie kontrole zaliczone','Open full report'=>'Otwórz pełny raport','Run a scan to see store health checks.'=>'Uruchom skanowanie, aby zobaczyć kontrole stanu sklepu.','%s critical store health issue detected'=>'Wykryto %s krytyczny problem ze stanem sklepu' . "\0" . 'Wykryto %s krytyczne problemy ze stanem sklepu' . "\0" . 'Wykryto %s krytycznych problemów ze stanem sklepu','Open the BrikControl report to see what to fix and which plugins can help.'=>'Otwórz raport BrikControl, aby zobaczyć, co naprawić i